style.css: @use "sass:math"; * { 	border: 0; 	box-sizing: border-box; 	margin: 0; 	padding: 0; } :root { 	--hue: 223; 	--bg: hsl(var(--hue), 90%, 50%); 	--front: hsl(var(--hue), 90%, 95%); 	--back: hsl(var(--hue), 90%, 5%); 	--trans-dur: 0.3s; 	font-size: clamp(1rem, 0.9rem + 0.5vw, 1.5rem); } body { 	background-color: var(--bg); 	color: var(--back); 	display: grid; 	place-items: center; 	font: 1em/1.5 -apple-system, BlinkMacSystemFont, "Helvetica Neue", Helvetica, sans-serif; 	height: 100vh; } .tot { 	position: relative; 	width: 20em; 	height: 20em; 	&__layer, 	&__tread { 		position: absolute; 		top: 50%; 		left: 50%; 	} 	&__layer { 		color: transparent; 		direction: ltr; 		font: { 			size: 3em; 			weight: 900; 		}; 		line-height: 1; 		transform: translate(-50%, -50%) rotateX(45deg) rotateZ(45deg); 		transform-style: preserve-3d; 	} 	&__tread { 		animation: { 			name: letter-tread-back; 			timing-function: linear; 			iteration-count: infinite; 		}; 		backface-visibility: hidden; 		color: var(--back); 		overflow: hidden; 		height: 100%; 		transform: translate(-50%, -50%); 		transition: color var(--trans-dur); 		&-window { 			&:before { 				content: attr(data-text); 				display: block; 				white-space: nowrap; 				transform: rotateY(180deg); 			} 		} 	} 	&__layer:last-child &__tread { 		animation-name: letter-tread-front; 		color: var(--front); 		&-window { 			&:before { 				transform: rotateY(0); 			} 		} 	} } /* Animations */ $treadHalf: 8rem; $treadRadius: 2rem; $treadCircle: 2 * math.$pi * $treadRadius; $treadLength: $treadHalf * 4 + $treadCircle; @debug $treadLength; @keyframes letter-tread-back { 	from { 		transform: translate(-50%, -50%) translateX(0) rotateY(0) translateZ(-$treadRadius); 	} 	#{($treadHalf / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX($treadHalf) rotateY(0) translateZ(-$treadRadius); 	} 	#{(($treadHalf + $treadCircle * 0.5) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX($treadHalf) rotateY(-180deg) translateZ(-$treadRadius); 	} 	#{(($treadHalf * 2 + $treadCircle * 0.5) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX(0) rotateY(-180deg) translateZ(-$treadRadius); 	} 	#{(($treadHalf * 3 + $treadCircle * 0.5) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX(-$treadHalf) rotateY(-180deg) translateZ(-$treadRadius); 	} 	#{(($treadHalf * 3 + $treadCircle) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX(-$treadHalf) rotateY(-360deg) translateZ(-$treadRadius); 	} 	to { 		transform: translate(-50%, -50%) translateX(0) rotateY(-360deg) translateZ(-$treadRadius); 	} } @keyframes letter-tread-front { 	from { 		transform: translate(-50%, -50%) translateX(0) rotateY(0) translateZ($treadRadius); 	} 	#{($treadHalf / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX(-$treadHalf) rotateY(0) translateZ($treadRadius); 	} 	#{(($treadHalf + $treadCircle * 0.5) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX(-$treadHalf) rotateY(-180deg) translateZ($treadRadius); 	} 	#{(($treadHalf * 2 + $treadCircle * 0.5) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX(0) rotateY(-180deg) translateZ($treadRadius); 	} 	#{(($treadHalf * 3 + $treadCircle * 0.5) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX($treadHalf) rotateY(-180deg) translateZ($treadRadius); 	} 	#{(($treadHalf * 3 + $treadCircle) / $treadLength) * 100%} { 		transform: translate(-50%, -50%) translateX($treadHalf) rotateY(-360deg) translateZ($treadRadius); 	} 	to { 		transform: translate(-50%, -50%) translateX(0) rotateY(-360deg) translateZ($treadRadius); 	} }
script.js: import React, { createContext, StrictMode, useContext, useState } from "https://esm.sh/react"; import { createRoot } from "https://esm.sh/react-dom/client"; const TextOnTreadContext = createContext<TextOnTreadContextType | undefined>(undefined); const TextOnTreadProvider: React.FC<TextOnTreadProviderProps> = ({ children, value }) => { const [text] = useState<string>(value); return ( <TextOnTreadContext.Provider value={{ text }}> {children} </TextOnTreadContext.Provider> ); }; createRoot(document.getElementById("root")!).render( 	<StrictMode> 		<TextOnTreadProvider value="RESILIENCE"> 			<TextOnTread /> 		</TextOnTreadProvider> 	</StrictMode> ); function TextOnTread() { 	const duration = 8000; // in ms 	const treadLength = 44.57; // from "https://esm.sh/$treadLength" in SCSS 	const treadFragments = 80; 	const treadFragmentWidth = treadLength / treadFragments; 	const backTreadArray: React.ReactNode[] = []; 	const frontTreadArray: React.ReactNode[] = []; 	for (let f = 0; f < treadFragments; ++f) { 		const backKey = `back-${f}`; 		const frontKey = `front-${f}`; 		const percent = f / treadFragments; 		const moveX = f * treadFragmentWidth; 		backTreadArray.push( 			<TextOnTreadFragment 				key={backKey} 				delay={-duration + (percent * duration)} 				duration={duration} 				moveX={-moveX} 				width={treadFragmentWidth} 			/> 		); 		frontTreadArray.push( 			<TextOnTreadFragment 				key={frontKey} 				delay={-duration + ((percent - 0.5) * duration)} 				duration={duration} 				moveX={moveX} 				width={treadFragmentWidth} 			/> 		); 	} 	return ( 		<div className="tot"> 			<TextOnTreadLayer layerFragments={frontTreadArray} /> 			<TextOnTreadLayer layerFragments={backTreadArray} ariaHidden={true} /> 		</div> 	); } function TextOnTreadFragment({ delay, duration, moveX, width }: TextOnTreadFragmentProps) { 	const context = useContext(TextOnTreadContext); 	if (!context) { throw new Error("`TextOnTreadFragment` must be used within `TextOnTreadProvider`"); } 	const { text } = context; 	const treadStyle = { 		animationDuration: `${duration}ms`, 		animationDelay: `${delay}ms`, 		width: `calc(${width}rem + 1px)` // extra 1px for bleed 	}; 	const windowStyle = { 		transform: `translateX(${moveX}rem)` 	}; 	return ( 		<div className="tot__tread" style={treadStyle}> 			<div className="tot__tread-window" aria-hidden="true" data-text={text} style={windowStyle}></div> 		</div> 	); } function TextOnTreadLayer({ layerFragments, ariaHidden }: TextOnTreadLayerProps) { 	const context = useContext(TextOnTreadContext); 	if (!context) { 		throw new Error("`TextOnTreadLayer` must be used within `TextOnTreadProvider`"); 	} 	const { text } = context; 	return ( 		<div className="tot__layer" aria-hidden={ariaHidden}> 			{text}{layerFragments} 		</div> 	); }
